    };

    // 修复：手写安全读取函数
    const getVal = (path, def) => {
      try {
        if (!globalVars) return def;
        const parts = path.split('.');
        let current = globalVars;
        for (const part of parts) {
          if (current === undefined || current === null) return def;
          current = current[part];
        }
        return current === undefined ? def : current;
      } catch (e) { return def; }
    };

    function updateAllData() {
      // 尝试获取全局变量，兼容不同的上下文环境
      if (typeof getAllVariables === 'function') {
        globalVars = getAllVariables();
      } else if (window.SillyTavern && SillyTavern.getContext) {
        globalVars = SillyTavern.getContext().variables;
      } else if (typeof extension_settings !== 'undefined' && extension_settings.mvu) {
        globalVars = extension_settings.mvu.variables;
      }
      updateOverview(); updateHaremList(); updateMinisterList(); updateBagList(); updateSkillList(); renderMap();
    }

    // (中间更新函数省略，保持不变)
    function updateOverview() { $('#time-display').text(`${getVal('stat_data.世界.年代', '未知')} · ${getVal('stat_data.世界.季节', '')}`); $('#location-display').text(getVal('stat_data.世界.当前地点', '虚空')); const hp = getVal('stat_data.宿主.状态.体力', 100); const mp = getVal('stat_data.宿主.状态.精力', 100); $('#hp-bar').css('width', `${Math.min(hp, 100)}%`); $('#hp-text').text(hp); $('#mp-bar').css('width', `${Math.min(mp, 100)}%`); $('#mp-text').text(mp); $('#res-gold').text(getVal('stat_data.宿主.资源.金钱', 0)); $('#res-food').text(getVal('stat_data.宿主.资源.粮草', 0)); $('#res-soldier').text(getVal('stat_data.宿主.资源.兵力', 0)); $('#res-point').text(getVal('stat_data.宿主.资源.霸业点', 0)); const stats = getVal('stat_data.宿主.属性', {}); $('#stat-ldr').text(stats.统率||0); $('#stat-str').text(stats.武力||0); $('#stat-int').text(stats.智力||0); $('#stat-pol').text(stats.政治||0); $('#stat-chr').text(stats.魅力||0); $('#quest-main').text(getVal('stat_data.系统.当前主线', '暂无')); const harem = getVal('stat_data.红颜录', {}); const count = Object.values(harem).filter(g => g.已攻略).length; $('#harem-count').text(`后宫: ${count} 人`); }
    function updateHaremList() { const harem = getVal('stat_data.红颜录', {}); const container = $('#harem-grid'); container.empty(); if (Object.keys(harem).length === 0) { container.html('<div style="grid-column:1/-1;text-align:center;opacity:0.6;">暂无红颜</div>'); return; } for (const [name, data] of Object.entries(harem)) { const love = data.好感度 || 0; let colorVar = 'var(--text-main)'; let barColor = '#bdbdbd'; if (love > 20) { colorVar = 'var(--text-highlight)'; barColor = '#81c784'; } if (love > 80) { colorVar = '#f48fb1'; barColor = '#f48fb1'; } if (data.已攻略) { colorVar = '#e91e63'; barColor = '#e91e63'; } container.append(`<div class="harem-card" onclick="openHaremDetail('${name}')"><div class="harem-name" style="color:${colorVar}">${name}</div><div class="harem-status">${data.状态||'正常'}</div><div class="harem-bar-mini"><div class="harem-bar-fill" style="width:${love}%;background:${barColor}"></div></div></div>`); } }
    window.openHaremDetail = function(name) { currentHaremTarget = name; const data = getVal(`stat_data.红颜录.${name}`, {}); $('#detail-name').text(name); $('#val-love').text(data.好感度 || 0); $('#val-loyalty').text(data.忠诚度 || 0); $('#val-lust').text(data.淫乱度 || 0); $('#val-status').text(data.状态 || '正常'); $('#val-location').text(data.所在地 || '未知'); $('#harem-detail').css('display', 'flex'); }; window.closeHaremDetail = function() { $('#harem-detail').hide(); }; window.haremAction = function(action) { const cmd = `${action}：${currentHaremTarget}`; if (typeof triggerSlash === 'function') triggerSlash(`/send ${cmd}`); else if (typeof send === 'function') send(cmd); };
    function updateMinisterList() { const harem = getVal('stat_data.红颜录', {}); const container = $('#minister-list'); container.empty(); if (Object.keys(harem).length === 0) { container.html('<div style="text-align:center;opacity:0.6;padding:20px;">麾下暂无文臣武将</div>'); return; } for (const [name, data] of Object.entries(harem)) { const stats = data.属性 || {统率:0,武力:0,智力:0,政治:0,魅力:0}; const skills = data.技能 || []; let skillsHtml = skills.length > 0 ? skills.map(s => `<span class="mini-skill-tag">${s}</span>`).join('') : '<span class="mini-skill-tag" style="opacity:0.5">无特殊技能</span>'; container.append(`<div class="minister-card"><div class="minister-header"><span class="minister-name">${name}</span><span class="minister-identity">${data.身份||'在野'}</span></div><div class="stats-bars-container"><div class="stat-bar-row"><span class="stat-label">统</span><div class="stat-track"><div class="stat-fill" style="width:${stats.统率}%;background:var(--stat-ldr)"></div></div><span class="stat-num">${stats.统率}</span></div><div class="stat-bar-row"><span class="stat-label">武</span><div class="stat-track"><div class="stat-fill" style="width:${stats.武力}%;background:var(--stat-str)"></div></div><span class="stat-num">${stats.武力}</span></div><div class="stat-bar-row"><span class="stat-label">智</span><div class="stat-track"><div class="stat-fill" style="width:${stats.智力}%;background:var(--stat-int)"></div></div><span class="stat-num">${stats.智力}</span></div><div class="stat-bar-row"><span class="stat-label">政</span><div class="stat-track"><div class="stat-fill" style="width:${stats.政治}%;background:var(--stat-pol)"></div></div><span class="stat-num">${stats.政治}</span></div></div><div class="minister-skills">${skillsHtml}</div></div>`); } }
    function updateBagList() { const bag = getVal('stat_data.宿主.背包', {}); const container = $('#bag-grid'); container.empty(); if (Object.keys(bag).length === 0) { container.html('<div style="grid-column:1/-1;text-align:center;opacity:0.6;">背包空空如也</div>'); return; } for (const [name, data] of Object.entries(bag)) { let typeClass = 'type-misc'; if (data.类型 === '装备') typeClass = 'type-equip'; else if (data.类型 === '消耗') typeClass = 'type-consum'; let useBtn = ''; if (data.类型 === '消耗') { useBtn = `<div class="item-use-btn" onclick="event.stopPropagation(); useItem('${name}')">使用</div>`; } container.append(`<div class="item-card" onclick="openItemDetail('${name}')"><div class="item-header"><span class="item-name">${name}</span><span class="item-count">x${data.数量||1}</span></div><span class="item-type ${typeClass}">${data.类型||'杂物'}</span><div class="item-desc">${data.描述||'暂无描述'}</div>${useBtn}</div>`); } }
    window.openItemDetail = function(name) { currentItemTarget = name; const data = getVal(`stat_data.宿主.背包.${name}`, {}); $('#item-detail-name').text(name); $('#item-detail-type').text(data.类型 || '杂物'); $('#item-detail-count').text(data.数量 || 1); $('#item-detail-desc').text(data.描述 || '暂无描述'); if (data.类型 === '消耗') $('#btn-use-item').show(); else $('#btn-use-item').hide(); $('#item-detail').css('display', 'flex'); }; window.closeItemDetail = function() { $('#item-detail').hide(); }; window.useItem = function(name) { const target = name || currentItemTarget; const cmd = `使用：${target}`; if (typeof triggerSlash === 'function') triggerSlash(`/send ${cmd}`); else if (typeof send === 'function') send(cmd); closeItemDetail(); };
    function updateSkillList() { const skills = getVal('stat_data.宿主.技能', {}); const container = $('#skill-list'); container.empty(); if (Object.keys(skills).length === 0) { container.html('<div style="text-align:center;opacity:0.6;padding:20px;">暂未领悟任何技能</div>'); return; } for (const [name, data] of Object.entries(skills)) { const isActive = data.类型 === '主动' || data.类型 === '统率'; const cardClass = isActive ? 'active-skill' : ''; container.append(`<div class="skill-card ${cardClass}"><div class="skill-info"><div class="skill-name">${name} <span class="skill-type">${data.类型||'被动'}</span></div><div class="skill-desc">${data.描述||'无描述'}</div></div><div class="skill-level"><div class="lv-badge">${data.等级||1}</div><div class="lv-label">Lv</div></div></div>`); } }

    // 重点修改：地图渲染函数，加入自动配色逻辑
    function renderMap() {
      const states = getVal('stat_data.世界.局势', {});
      const currentLocation = getVal('stat_data.世界.当前地点', '');

      // 解析当前位置属于哪个州
      let userProvince = '';
      for (const pName in mapPaths) { if (currentLocation.includes(pName)) { userProvince = pName; break; } }
      if (!userProvince) { for (const [city, prov] of Object.entries(locationMap)) { if (currentLocation.includes(city)) { userProvince = prov; break; } } }

      $('#map-title-mini').text(`🌏 天下大势`);
      let svgContent = '';
      for (const [name, pathInfo] of Object.entries(mapPaths)) {
        const stateInfo = states[name] || { 控制者: '未知' };
        let owner = stateInfo.控制者 || '未知';

        // 自动计算颜色
        let color = stateInfo.颜色;
        if (!color) {
            // 如果后端没给颜色，前端根据控制者名字自动匹配
            if (owner.includes('曹')) color = colorMap['曹魏'];
            else if (owner.includes('刘') && (owner.includes('备') || owner.includes('禅'))) color = colorMap['蜀汉'];
            else if (owner.includes('孙')) color = colorMap['东吴'];
            else if (owner.includes('袁')) color = colorMap['袁绍'];
            else if (owner.includes('董') || owner.includes('吕')) color = colorMap['董卓'];
            else if (owner.includes('蛮') || owner.includes('越')) color = colorMap['南蛮'];
            else if (owner.includes('长史')) color = colorMap['西域'];
            else color = '#e0e0e0'; // 默认灰色
        }

        svgContent += `<path class="province" d="${pathInfo.d}" fill="${color}"
                         onmousedown="window.onProvinceClick(event, '${name}', '${owner}')"></path>`;
        if (settings.showLabels) svgContent += `<text class="map-text" x="${pathInfo.x}" y="${pathInfo.y}">${name}</text>`;

        if (name === userProvince) {
          svgContent += `<circle class="player-marker" cx="${pathInfo.x}" cy="${pathInfo.y}" r="6"></circle>`;
        }
      }
      $('#map-svg').html(svgContent);
    }

    // (后续辅助函数保持不变)
    function setTransform() { $('#map-transform-layer').css('transform', `translate(${mapState.pointX}px, ${mapState.pointY}px) scale(${mapState.scale})`); }
    window.mapZoomIn = function() { mapState.scale *= 1.2; setTransform(); };
    window.mapZoomOut = function() { mapState.scale /= 1.2; setTransform(); };
    window.mapReset = function() { mapState = { scale: 1, panning: false, pointX: 0, pointY: 0, startX: 0, startY: 0 }; setTransform(); };
    function bindMapEvents() {
        const $wrapper = $('.map-wrapper-inner');
        $wrapper.on('mousedown', function(e) { if ($(e.target).closest('.tactical-menu, .map-header-mini, .zoom-controls').length) return; e.preventDefault(); mapState.startX = e.clientX - mapState.pointX; mapState.startY = e.clientY - mapState.pointY; mapState.panning = true; mapState.clickStartX = e.clientX; mapState.clickStartY = e.clientY; });
        $wrapper.on('mousemove', function(e) { if (!mapState.panning) return; e.preventDefault(); mapState.pointX = e.clientX - mapState.startX; mapState.pointY = e.clientY - mapState.startY; setTransform(); });
        $wrapper.on('mouseup mouseleave', function() { mapState.panning = false; });
        $wrapper.on('wheel', function(e) { e.preventDefault(); const delta = e.originalEvent.deltaY; const scaleAmount = 1.1; if (delta > 0) mapState.scale /= scaleAmount; else mapState.scale *= scaleAmount; setTransform(); });
    }
    window.onProvinceClick = function(e, name, owner) { const dist = Math.sqrt(Math.pow(e.clientX - mapState.clickStartX, 2) + Math.pow(e.clientY - mapState.clickStartY, 2)); if (dist < 5) window.openTacticalMenu(name, owner); };
    window.switchTab = function(tabId) { $('.tab-content').removeClass('active'); $(`#tab-${tabId}`).addClass('active'); $('.nav-btn').removeClass('active'); $(`#btn-${tabId}`).addClass('active'); if(tabId==='map') renderMap(); if(tabId==='harem') updateHaremList(); if(tabId==='minister') updateMinisterList(); if(tabId==='bag') updateBagList(); if(tabId==='skill') updateSkillList(); };
    window.toggleTheme = function() { settings.dayMode = !settings.dayMode; const panel = document.querySelector('.lord-panel'); if (settings.dayMode) { panel.setAttribute('data-theme', 'day'); $('#btn-theme-switch').addClass('on'); } else { panel.setAttribute('data-theme', 'night'); $('#btn-theme-switch').removeClass('on'); } };
    window.toggleLabels = function() { settings.showLabels = !settings.showLabels; if (settings.showLabels) $('#btn-label-switch').addClass('on'); else $('#btn-label-switch').removeClass('on'); renderMap(); };
    window.refreshData = function() { updateAllData(); alert('系统数据已刷新！'); };
    window.resetSystem = function() { if(confirm('确定重置？')) { if (typeof triggerSlash === 'function') triggerSlash(`/send [系统指令：重置变量]`); else alert('请手动输入 "/mvu_reset"'); } };
    window.openTacticalMenu = function(name, owner) { currentMapTarget = name; $('#menu-place').text(name); $('#menu-owner').text(`控制者: ${owner}`); $('#tactical-menu').show(); };
    window.closeTacticalMenu = function() { $('#tactical-menu').hide(); };
    window.sendAction = function(action) { const cmd = `${action}：${currentMapTarget}`; if (typeof triggerSlash === 'function') triggerSlash(`/send ${cmd}`); else if (typeof send === 'function') send(cmd); closeTacticalMenu(); };

    async function init() {
        if (typeof waitGlobalInitialized === 'function') {
            try { await waitGlobalInitialized('Mvu'); } catch(e) { console.warn('Mvu init wait failed', e); }
        }
        updateAllData();
        if (typeof Mvu !== 'undefined' && Mvu.events) {
            eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, updateAllData);
        } else if (typeof eventOn === 'function') {
            try { eventOn('character_message_rendered', updateAllData); } catch(e) {}
        }
        setTimeout(bindMapEvents, 500);
    }
    if (typeof errorCatched === 'function') { $(errorCatched(init)); } else { $(init); }
  </script>
