            --bg-pattern: radial-gradient(circle at 50% 0, #3e2723 0%, transparent 70%), repeating-linear-gradient(45deg, rgba(193, 160, 110, 0.05) 0px, rgba(193, 160, 110, 0.05) 2px, transparent 2px, transparent 10px);
