    <!-- 核心稳健解析：隐藏数据源 -->
    <div id="rawData" style="display:none;"><ancient_scroll>$1</ancient_scroll></div>

    <div class="story-panel" id="main-panel">
        <div class="content-wrapper">
            <div class="loading">正在展卷...</div>
        </div>
    </div>

    <script>
        // ========== 解析核心 ==========
        function parseXML() {
            const rawEl = document.getElementById('rawData');
            if (!rawEl) return null;

            // 获取HTML内容并处理转义
            let xmlText = rawEl.innerHTML;
            const textarea = document.createElement('textarea');
            textarea.innerHTML = xmlText;
            xmlText = textarea.value.trim();

            console.log("解析长度:", xmlText.length);

            const result = {
                meta: { time: '未知', place: '未知' },
                content: ''
            };

            try {
                // --- 提取元信息 ---
                let metaBlock = xmlText.substring(0, 1000);
                const extract = (key) => {
                    const regex = new RegExp(`\\[\\s*${key}\\s*[\\|\\:]\\s*([^\\]]+)\\]`, 'i');
                    const m = metaBlock.match(regex);
                    return m ? m[1].trim() : null;
                };

                result.meta.time = extract('时间') || '未知';
                result.meta.place = extract('地点') || '未知';

                // --- 提取正文 ---
                let contentRaw = '';

                // 1. 标准标签匹配
                const strictMatch = xmlText.match(/<story_content>([\s\S]*?)<\/story_content>/i);

                if (strictMatch && strictMatch[1]) {
                    contentRaw = strictMatch[1];
                } else {
                    // 2. 兜底策略
                    const openMatch = xmlText.match(/<story_content>([\s\S]*?)(?=<\/ancient_scroll>|$)/i);
                    if (openMatch && openMatch[1]) {
                        contentRaw = openMatch[1];
                    } else {
                        // 3. 终极兜底
                        const parts = xmlText.split(/<\/meta_info>/i);
                        if (parts.length > 1) {
                            contentRaw = parts[1].replace(/<\/?story_content>/gi, '').replace(/<\/ancient_scroll>/gi, '');
                        } else {
                            contentRaw = xmlText;
                        }
                    }
                }

                result.content = contentRaw.trim();
                return result;

            } catch (e) {
                console.error(e);
                result.content = "解析发生错误：" + e.message;
                return result;
            }
        }

        // ========== 渲染界面 ==========
        function renderPage() {
            try {
                const data = parseXML();
                if (!data) throw new Error("无法读取数据源");

                // 处理正文换行
                let raw = data.content;
                raw = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
                const paragraphs = raw.split('\n').filter(p => p.trim());

                let contentHtml = '';
                if (paragraphs.length > 0) {
                    contentHtml = paragraphs.map(p => `<p>${p}</p>`).join('');
                } else {
                    contentHtml = `<p>${raw}</p>`;
                }

                // 渲染：结构简化，直接平铺
                const html = `
                    <div class="content-wrapper">
                        <div class="story-header">
                            <div class="story-meta">
                                <span>📅 ${data.meta.time}</span>
                                <span>📍 ${data.meta.place}</span>
                            </div>
                        </div>

                        <div class="story-content">
                            ${contentHtml}
                        </div>
                    </div>
                `;

                document.getElementById('main-panel').innerHTML = html;

            } catch (e) {
                console.error(e);
                document.getElementById('main-panel').innerHTML =
                    '<div class="loading" style="color:#e57373">❌ 渲染失败：' + e.message + '</div>';
            }
        }

        // 延迟执行确保加载
        setTimeout(renderPage, 100);
    </script>
</body>
</html>
