        // 状态管理
        let state = {
            timeline: null,
            location: null,
            name: '',
            age: '20',
            gender: '男',
            mode: '身穿'
        };

        function parseXML(xml) {
            const data = { status: '', player: '', timelines: [], locations: [] };
            try {
                const statusMatch = xml.match(/\[当前状态\|([^\]]+)\]/);
                if (statusMatch) data.status = statusMatch[1];
                const playerMatch = xml.match(/\[玩家ID\|([^\]]+)\]/);
                if (playerMatch) data.player = playerMatch[1];

                const timelineBlock = xml.match(/<timelines>([\s\S]*?)<\/timelines>/);
                if (timelineBlock) {
                    const regex = /\[选项\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                    let match;
                    while ((match = regex.exec(timelineBlock[1])) !== null) {
                        data.timelines.push({
                            code: match[1], title: match[2], year: match[3], stars: match[4],
                            brief: match[5], situation: match[6], recommend: match[7]
                        });
                    }
                }

                const locBlock = xml.match(/<locations>([\s\S]*?)<\/locations>/);
                if (locBlock) {
                    const regex = /\[地点\|([^\|]+)\|([^\]]+)\]/g;
                    let match;
                    while ((match = regex.exec(locBlock[1])) !== null) {
                        data.locations.push({ name: match[1], desc: match[2] });
                    }
                }
                return data;
            } catch (e) { console.error(e); return null; }
        }

        function render() {
            const data = parseXML(rawXML);
            if (!data) return;

            if (!state.location && data.locations.length > 0) state.location = data.locations[0].name;
            if (!state.name && data.player) state.name = data.player;

            let timelineHTML = '';
            data.timelines.forEach(t => {
                const isActive = state.timeline?.code === t.code;
                timelineHTML += `
                    <div class="timeline-card ${isActive ? 'active' : ''}"
                         onclick="selectTimeline('${t.code}')">
                        <div class="card-header">
                            <span class="card-title">${t.code}. ${t.title}</span>
                            <span class="card-year">${t.year}</span>
                        </div>
                        <div class="card-brief">${t.brief}</div>
                        <span class="card-stars">天命难度: ${t.stars}</span>
                    </div>
                `;
            });

            let detailHTML = '<div class="detail-placeholder">请于左侧选择时间锚点以观天机...</div>';
            if (state.timeline) {
                const t = data.timelines.find(item => item.code === state.timeline.code);
                if (t) {
                    detailHTML = `
                        <div style="text-align:center; margin-bottom:10px; border-bottom:1px solid #d7ccc8; padding-bottom:8px;">
                            <h2 style="color:#bf360c; margin:0; font-family:'LiSu',serif; font-size:1.6em;">${t.title}</h2>
                            <div style="color:#5d4037; font-family:'KaiTi',serif; font-size:0.9em;">${t.year}</div>
                        </div>
                        <div class="detail-section">
                            <span class="detail-label">◈ 天下大势</span>
                            <div class="detail-text">${t.situation}</div>
                        </div>
                        <div class="detail-section">
                            <span class="detail-label">◈ 鬼谷谏言</span>
                            <div class="detail-text">${t.recommend}</div>
                        </div>
                    `;
                }
            }

            let locOptions = '';
            data.locations.forEach(l => {
                locOptions += `<option value="${l.name}" ${state.location === l.name ? 'selected' : ''}>${l.name} - ${l.desc}</option>`;
            });

            const html = `
                <div class="login-container">
                    <div class="header">
                        <div class="sys-title">汉末霸业 · 轮回天枢</div>
                        <div class="sys-status">
                            宿主: ${data.player}<br>
                            状态: ${data.status} <span style="color:#81c784">✦</span>
                        </div>
                    </div>

                    <div class="main-body">
                        <div class="timeline-col">
                            <div class="group-label">选择时间锚点</div>
                            ${timelineHTML}
                        </div>

                        <div class="config-col">
                            <div class="detail-panel">${detailHTML}</div>

                            <div class="group-label">身份通牒录入</div>
                            <div class="form-panel">
                                <div class="form-row">
                                    <div class="form-group" style="flex:2;">
                                        <div class="sub-label">姓名</div>
                                        <input type="text" class="sys-input" value="${state.name}" oninput="updateState('name', this.value)">
                                    </div>
                                    <div class="form-group">
                                        <div class="sub-label">年龄</div>
                                        <input type="number" class="sys-input" value="${state.age}" min="10" max="99" oninput="updateState('age', this.value)">
                                    </div>
                                </div>
                                <div class="form-row">
                                    <div class="form-group">
                                        <div class="sub-label">性别</div>
                                        <div class="radio-group">
                                            <div class="radio-option ${state.gender==='男'?'selected':''}" onclick="updateState('gender', '男')">男</div>
                                            <div class="radio-option ${state.gender==='女'?'selected':''}" onclick="updateState('gender', '女')">女</div>
                                        </div>
                                    </div>
                                    <div class="form-group" style="flex:2;">
                                        <div class="sub-label">降临方式</div>
                                        <div class="radio-group">
                                            <div class="radio-option ${state.mode==='身穿'?'selected':''}" onclick="updateState('mode', '身穿')">⚡ 身穿</div>
                                            <div class="radio-option ${state.mode==='魂穿'?'selected':''}" onclick="updateState('mode', '魂穿')">🌀 魂穿</div>
                                        </div>
                                    </div>
                                </div>
                                <div class="form-group">
                                    <div class="sub-label">降临州郡</div>
                                    <select class="sys-select" onchange="updateState('location', this.value)">
                                        ${locOptions}
                                    </select>
                                </div>
                            </div>

                            <div class="action-area">
                                <button class="launch-btn" onclick="launch()" ${!state.timeline ? 'disabled' : ''}>
                                    启动穿越
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            `;

            document.getElementById('login-root').innerHTML = html;
        }

        window.updateState = function(key, value) {
            state[key] = value;
            if (key === 'gender' || key === 'mode') render();
        };

        window.selectTimeline = function(code) {
            state.timeline = { code };
            render();
        };

        // 核心修改：在发送指令的同时，尝试静默更新 MVU 变量
        window.launch = function() {
            if (!state.timeline) return;
            const data = parseXML(rawXML);
            const t = data.timelines.find(item => item.code === state.timeline.code);
            const title = t ? t.title : state.timeline.code;

            // 1. 尝试执行 MVU 变量初始化
            const mvuConfig = MVU_CONFIGS[state.timeline.code];
            if (mvuConfig) {
                const updates = [
                    { op: 'replace', path: '/stat_data/世界/年代', value: t.year },
                    { op: 'replace', path: '/stat_data/世界/季节', value: mvuConfig.season },
                    { op: 'replace', path: '/stat_data/系统/当前主线', value: mvuConfig.main },
                    { op: 'replace', path: '/stat_data/世界/当前地点', value: state.location }
                ];

                // 添加各州控制者更新指令
                for (const [stateName, stateData] of Object.entries(mvuConfig.states)) {
                    updates.push({
                        op: 'insert',
                        path: `/stat_data/世界/局势/${stateName}`,
                        value: stateData
                    });
                }

                // 尝试调用 ST 环境命令
                try {
                    const command = `/mvu_set ${JSON.stringify(updates)}`;
                    if (window.SillyTavern && window.SillyTavern.getContext) {
                        window.SillyTavern.getContext().executeCommand(command);
                        console.log("MVU data initialized silently.");
                    } else {
                        // 如果不是 ST 环境，或者没法直接调用，这步会跳过，不影响后续文本发送
                        console.warn("MVU auto-init skipped (environment not detected).");
                    }
                } catch(e) { console.warn("MVU auto-init failed", e); }
            }

            // 2. 生成并发送剧情触发指令
            const cmd = `系统指令：确认穿越！
时间线：[${title}]
降临点：[${state.location}]
身份：[${state.name} / ${state.gender} / ${state.age}岁]
方式：[${state.mode}]`;

            // 尝试获取输入框并填充
            try {
                let textarea = document.getElementById('send_textarea');
                // 兼容性处理：尝试查找父级框架中的输入框
                if (!textarea && window.parent) {
                    textarea = window.parent.document.getElementById('send_textarea');
                }

                if (textarea) {
                    textarea.value = cmd;
                    // 触发 input 事件以通知 ST 界面（如调整高度）
                    textarea.dispatchEvent(new Event('input', { bubbles: true }));
                    textarea.focus();
                } else {
                    // 如果找不到输入框（极端情况），回退到弹窗
                    alert("指令已生成，请手动复制发送：\n\n" + cmd);
                }
            } catch (e) {
                console.error("自动填充失败", e);
                alert("指令已生成，请手动复制发送：\n\n" + cmd);
            }
        };

        render();
    </script>
</body>
</html>
