    // 2. 提取关键信息
    const timeMatch = message.match(/时间线：\[(.*?)\]/);
    const locMatch = message.match(/降临点：\[(.*?)\]/);

    if (!timeMatch) return;

    const scenarioKey = timeMatch[1];
    const location = locMatch ? locMatch[1] : '未知';
    const targetData = SCENARIO_DATA[scenarioKey];

    if (!targetData) {
        console.warn(`[MVU初始化] 未找到剧本数据: ${scenarioKey}`);
        return;
    }

    console.log(`[MVU初始化] 检测到穿越指令，正在加载剧本: ${scenarioKey}`);

    // 3. 构造更新指令 (JSON Patch)
    // 注意：我们配合之前的"变量结构.js"，只需设置控制者，颜色会自动计算
    const updates = [
        { op: 'replace', path: '/stat_data/世界/局势', value: targetData.局势 },
        { op: 'replace', path: '/stat_data/世界/年代', value: targetData.年代 },
        { op: 'replace', path: '/stat_data/世界/当前地点', value: location }
        // 你还可以在这里添加更多初始资源的设置，比如根据剧本难度调整初始金钱
    ];

    // 4. 执行更新
    // 延时一小会儿确保 MVU 系统已就绪，且不影响消息本身的发送流程
    setTimeout(() => {
        if (window.Mvu && window.Mvu.updateVariables) {
            window.Mvu.updateVariables(updates);
            toastr.success(`已加载剧本：${scenarioKey}`, '汉末霸业系统');
        } else {
            console.error('[MVU初始化] MVU插件未加载，无法更新变量');
        }
    }, 500);
};

// 注册事件监听
if (window.eventOn) {
    window.eventOn('chat_message_sent', onMessageSent);
} else {
    // 兼容旧版或不同环境
    console.warn('[MVU初始化] 未找到 eventOn 函数，尝试手动挂载');
    const oldSend = window.send; // 假设有一个全局 send 函数
    if (typeof oldSend === 'function') {
        window.send = function(...args) {
            onMessageSent(args[0]); // 先处理我们的逻辑
            return oldSend.apply(this, args); // 再执行原逻辑
        };
    }
}

entries.content:
---
变量更新规则:
  世界:
    年代:
      check:
        - 随着剧情推进、重大战役结束或时间跳跃时更新
        - 格式推荐为“建安XX年”或“公元XXXX年”
    季节:
      check:
        - 每过3个月或剧情明确提及换季（春耕、夏耘、秋收、冬藏）时更新
    当前地点:
      check:
        - 宿主移动、行军或传送时更新，保持地理位置准确
        - 地点名应尽量与地图上的州名或名城对应（如：洛阳、邺城、建业）
    局势:
      type: |-
        {
          [州名: string]: {
            控制者: string; // 势力君主名，如 曹操、刘备
            颜色: string;   // HTML颜色代码，严格参考下方色卡
          }
        }
      check:
        - 当发生攻城掠地、势力灭亡或外交归顺时更新
        - 更新控制者时，必须同步更新颜色代码。参考色卡：汉室/朝廷(#b71c1c)、曹魏(#1976d2)、蜀汉(#d32f2f)、东吴(#388e3c)、袁绍(#fbc02d)、董卓/凉州(#5d4037)、异族(#e64a19)、西域(#00796b)、黄巾(#fdd835)、无主(#e0e0e0)

  宿主:
    状态.${体力|精力}:
      type: number
      range: 0~100
      check:
        - 战斗、长途行军、高强度脑力活动、夜间房事后扣除
        - 休息、睡眠、服用药物后恢复
        - 体力过低（<20）时应在剧情中体现疲惫感
    资源.${金钱|粮草|兵力|霸业点}:
      type: number
      min: 0
      check:
        - 交易、征兵、战争消耗或获得系统奖励时更新
        - 霸业点：达成成就、攻略名将、占领城池时增加
    属性.${统率|武力|智力|政治|魅力}:
      type: number
      range: 0~120
      check:
        - 锻炼、读书、系统加点或获得特殊宝物时提升
        - 单次提升幅度通常为 1-5 点，除非有神级奇遇
    背包:
      type: |-
        {
          [物品名: string]: {
            类型: '装备' | '消耗' | '杂物';
            数量: number;
            描述: string;
          }
        }
      check:
        - 获得战利品、购买道具、开启礼包时添加
        - 剧情中使用了消耗品或赠送礼物时数量减 1，归零则移除
    技能:
      type: |-
        {
          [技能名: string]: {
            类型: '主动' | '被动' | '统率';
            描述: string;
            等级: number;
          }
        }
      check:
        - 领悟新技能或现有技能升级时更新

  紅颜录:
    type: |-
      {
        [角色名: string]: {
          身份: string;
          所在地: string;
          状态: string;   // 如：正常、怀孕、囚禁、兴奋
          好感度: number; // 0-100
          忠诚度: number; // 0-100
          淫乱度: number; // 0-100
          已攻略: boolean;
          属性: {
            统率: number;
            武力: number;
            智力: number;
            政治: number;
            魅力: number;
          };
          技能: string[]; // 角色特技列表
        }
      }
    check:
      - 好感度：根据互动、送礼、对话选择进行增减（0-20敌视, 80+爱慕）
      - 忠诚度：受宿主威望、恩赏影响，过低可能叛变
      - 淫乱度：随亲密行为深度、调教次数提升
      - 已攻略：发生实质关系（如洞房、誓约）后置为 true
      - 状态：随剧情实时更新，如怀孕需有前置行为

  系统:
    当前主线:
      check:
        - 当前阶段目标完成后，更新为下一阶段目标

---
变量输出格式:
  rule:
    - you must output the update analysis and the actual update commands at once in the end of the next reply
    - the update commands works like the **JSON Patch (RFC 6902)** standard, must be a valid JSON array containing operation objects, but supports the following operations instead:
      - replace: replace the value of existing paths
      - delta: update the value of existing number paths by a delta value
      - insert: insert new items into an object or array (using `-` as array index intends appending to the end)
      - remove
      - move
    - don't update field names starts with `_` as they are readonly, such as `_变量`
  format: |-
    <UpdateVariable>
    <div style="width: 80%; margin: 20px auto;">
      <details class="night-sky-complete" style="
        background: linear-gradient(135deg, #0f172a 0%, #1e3a5f 50%, #0f172a 100%);
        border: 1px solid rgba(251, 191, 36, 0.3);
        border-radius: 18px;
        box-shadow:
          0 4px 24px rgba(251, 191, 36, 0.2),
          0 0 40px rgba(251, 191, 36, 0.1),
          inset 0 1px 0 rgba(251, 191, 36, 0.1);
        transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
        overflow: hidden;
        position: relative;
      ">
        <summary style="
          padding: 16px 24px;
          color: #fef3c7;
          cursor: pointer;
          list-style: none;
          font-weight: 500;
          position: relative;
          display: flex;
          align-items: center;
          gap: 10px;
          z-index: 2;
        ">
          <span style="
            font-size: 1.3em;
            filter: drop-shadow(0 0 14px rgba(251, 191, 36, 0.9));
            position: relative;
          ">🌕
            <span style="
              position: absolute;
              top: 50%;
              left: 50%;
              transform: translate(-50%, -50%);
              width: 140%;
              height: 140%;
              background: radial-gradient(circle, rgba(251, 191, 36, 0.2) 0%, transparent 70%);
              border-radius: 50%;
              animation: moon-halo 3s ease-in-out infinite;
            "></span>
          </span>
          <span style="flex: 1;">月圆思成，思路清晰</span>
          <span style="font-size: 0.9em; opacity: 0.8;">✨</span>
          <small style="color: #fde68a; font-size: 0.85em; margin-left: 8px;">
            <span class="toggle-indicator" data-close="展开思绪 ▶" data-open="收起 ▼"></span>
          </small>
          <span class="stars-sparkle" style="
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background-image:
              radial-gradient(circle at 15% 30%, rgba(251, 191, 36, 0.15) 1px, transparent 1px),
              radial-gradient(circle at 75% 60%, rgba(251, 191, 36, 0.12) 1px, transparent 1px),
              radial-gradient(circle at 45% 70%, rgba(251, 191, 36, 0.1) 1px, transparent 1px),
              radial-gradient(circle at 85% 25%, rgba(251, 191, 36, 0.13) 1px, transparent 1px);
            background-size: 100% 100%;
            animation: stars-twinkle 2s ease-in-out infinite;
            pointer-events: none;
          "></span>
        </summary>
        <div style="
          max-height: 320px;
          overflow-y: auto;
          padding: 14px 24px;
          color: #cbd5e1;
          line-height: 1.7;
          transition: all 0.3s ease;
          white-space: pre-wrap;
          background: rgba(15, 23, 42, 0.4);
          font-family: monospace;
          font-size: 0.9em;
        ">
    <Analysis>$(IN ENGLISH, no more than 80 words)
    - ${calculate time passed: ...}
    - ${decide whether dramatic updates are allowed as it's in a special case or the time passed is more than usual: yes/no}
    - ${analyze every variable based on its corresponding `check`, according only to current reply instead of previous plots: ...}
    </Analysis>
    <JSONPatch>
    [
      { "op": "replace", "path": "${/path/to/variable}", "value": "${new_value}" },
      { "op": "delta", "path": "${/path/to/number/variable}", "value": "${positive_or_negative_delta}" },
      { "op": "insert", "path": "${/path/to/object/new_key}", "value": "${new_value}" },
      { "op": "insert", "path": "${/path/to/array/-}", "value": "${new_value}" },
      { "op": "remove", "path": "${/path/to/object/key}" },
      { "op": "remove", "path": "${/path/to/array/0}" },
      { "op": "move", "from": "${/path/to/variable}", "to": "${/path/to/another/path}" },
      ...
    ]
    </JSONPatch>
        </div>
      </details>
    </div>

    <style>
      .night-sky-complete::-webkit-scrollbar { width: 6px; }
      .night-sky-complete::-webkit-scrollbar-track { background: #0f172a; }
      .night-sky-complete::-webkit-scrollbar-thumb { background: rgba(251, 191, 36, 0.3); border-radius: 3px; }
      .night-sky-complete::-webkit-scrollbar-thumb:hover { background: rgba(251, 191, 36, 0.5); }
      .night-sky-complete[open] { box-shadow: 0 8px 40px rgba(251, 191, 36, 0.3), 0 0 60px rgba(251, 191, 36, 0.15), inset 0 1px 0 rgba(251, 191, 36, 0.2) !important; border-color: rgba(251, 191, 36, 0.5) !important; }
      .night-sky-complete[open] > div { animation: contentSlideIn 0.4s ease forwards; }
      .night-sky-complete summary:hover { background: rgba(251, 191, 36, 0.05); }
      .night-sky-complete[open] summary { border-bottom: 1px solid rgba(251, 191, 36, 0.25); background: rgba(30, 58, 95, 0.3); }
      .night-sky-complete summary::marker { display: none; }
      .night-sky-complete[open] .toggle-indicator::after { content: attr(data-open); }
      .night-sky-complete:not([open]) .toggle-indicator::after { content: attr(data-close); }
      @keyframes moon-halo { 0%, 100% { opacity: 0.4; transform: translate(-50%, -50%) scale(1); } 50% { opacity: 0.7; transform: translate(-50%, -50%) scale(1.2); } }
      @keyframes stars-twinkle { 0%, 100% { opacity: 0.6; } 50% { opacity: 1; } }
      @keyframes contentSlideIn { from { opacity: 0; transform: translateY(-10px); } to { opacity: 1; transform: translateY(0); } }
    </style>

    </div>
  </details>
</div>

<style>
  .night-sky-complete::-webkit-scrollbar {
    width: 6px;
  }
  .night-sky-complete::-webkit-scrollbar-track {
    background: #0f172a;
  }
  .night-sky-complete::-webkit-scrollbar-thumb {
    background: rgba(251, 191, 36, 0.3);
    border-radius: 3px;
  }
  .night-sky-complete::-webkit-scrollbar-thumb:hover {
    background: rgba(251, 191, 36, 0.5);
  }

  .night-sky-complete[open] {
    box-shadow: 
      0 8px 40px rgba(251, 191, 36, 0.3),
      0 0 60px rgba(251, 191, 36, 0.15),
      inset 0 1px 0 rgba(251, 191, 36, 0.2) !important;
    border-color: rgba(251, 191, 36, 0.5) !important;
  }
  .night-sky-complete[open] > div {
    animation: contentSlideIn 0.4s ease forwards;
  }

  .night-sky-complete summary:hover {
    background: rgba(251, 191, 36, 0.05);
  }
  .night-sky-complete[open] summary {
    border-bottom: 1px solid rgba(251, 191, 36, 0.25);
    background: rgba(30, 58, 95, 0.3);
  }
  .night-sky-complete summary::marker {
    display: none;
  }

  .night-sky-complete[open] .toggle-indicator::after {
    content: attr(data-open);
  }
  .night-sky-complete:not([open]) .toggle-indicator::after {
    content: attr(data-close);
  }

  @keyframes moon-halo {
    0%, 100% {
      opacity: 0.4;
      transform: translate(-50%, -50%) scale(1);
    }
    50% {
      opacity: 0.7;
      transform: translate(-50%, -50%) scale(1.2);
    }
  }

  @keyframes stars-twinkle {
    0%, 100% {
      opacity: 0.6;
    }
    50% {
      opacity: 1;
    }
  }

  @keyframes contentSlideIn {
    from {
      opacity: 0;
      transform: translateY(-10px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }
</style>
